+
+vi.mock("../plugins/provider-discovery.js", () => ({
+  resolveRuntimePluginDiscoveryProviders: mocks.resolveRuntimePluginDiscoveryProviders,
+  runProviderCatalog: mocks.runProviderCatalog,
